import React, { useEffect, useMemo, useState } from "react";
import {
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  Legend,
  Line,
  LineChart,
  Pie,
  PieChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis
} from "recharts";

function Dashboard() {
  const [sensorData, setSensorData] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        setError("");

        const [sensorResponse, alertsResponse] = await Promise.all([
          fetch("http://localhost:5000/sensor-data"),
          fetch("http://localhost:5000/alerts")
        ]);

        if (!sensorResponse.ok || !alertsResponse.ok) {
          throw new Error("Unable to fetch dashboard data");
        }

        const sensorJson = await sensorResponse.json();
        const alertsJson = await alertsResponse.json();

        setSensorData(Array.isArray(sensorJson?.data) ? sensorJson.data : []);
        setAlerts(Array.isArray(alertsJson?.data) ? alertsJson.data : []);
      } catch (err) {
        setError(err.message || "Failed to load dashboard");
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  const kpi = useMemo(() => {
    const uniqueDrains = new Set(sensorData.map((row) => row.drain_id)).size;
    const totalAlerts = alerts.length;
    const highRiskAlerts = alerts.filter(
      (row) => String(row.severity || "").toUpperCase() === "HIGH"
    ).length;

    const avgDhi = sensorData.length
      ? sensorData.reduce((sum, row) => sum + Number(row.dhi_score || 0), 0) /
        sensorData.length
      : 0;

    return {
      totalDrains: uniqueDrains,
      totalAlerts,
      highRiskAlerts,
      averageDhi: avgDhi
    };
  }, [sensorData, alerts]);

  const lineData = useMemo(
    () =>
      sensorData
        .slice(0, 20)
        .reverse()
        .map((row) => ({
          timestamp: row.timestamp,
          timeLabel: new Date(row.timestamp).toLocaleTimeString([], {
            hour: "2-digit",
            minute: "2-digit"
          }),
          dhi_score: Number(row.dhi_score || 0)
        })),
    [sensorData]
  );

  const pieData = useMemo(() => {
    const severityMap = { HIGH: 0, MEDIUM: 0, LOW: 0 };
    alerts.forEach((row) => {
      const key = String(row.severity || "").toUpperCase();
      if (severityMap[key] !== undefined) {
        severityMap[key] += 1;
      }
    });

    return [
      { name: "HIGH", value: severityMap.HIGH, color: "#e53935" },
      { name: "MEDIUM", value: severityMap.MEDIUM, color: "#fb8c00" },
      { name: "LOW", value: severityMap.LOW, color: "#43a047" }
    ];
  }, [alerts]);

  const topRiskDrains = useMemo(() => {
    const grouped = sensorData.reduce((acc, row) => {
      const id = row.drain_id;
      if (!acc[id]) {
        acc[id] = { drain_id: id, sum: 0, count: 0 };
      }

      acc[id].sum += Number(row.dhi_score || 0);
      acc[id].count += 1;
      return acc;
    }, {});

    return Object.values(grouped)
      .map((item) => ({
        drain_id: String(item.drain_id),
        avg_dhi: Number((item.sum / item.count).toFixed(2))
      }))
      .sort((a, b) => b.avg_dhi - a.avg_dhi)
      .slice(0, 5);
  }, [sensorData]);

  if (loading) {
    return (
      <section className="stats-section">
        <div className="container">
          <div className="dashboard-state-card">Loading dashboard...</div>
        </div>
      </section>
    );
  }

  if (error) {
    return (
      <section className="stats-section">
        <div className="container">
          <div className="dashboard-state-card dashboard-state-error">{error}</div>
        </div>
      </section>
    );
  }

  if (!sensorData.length && !alerts.length) {
    return (
      <section className="stats-section">
        <div className="container">
          <div className="dashboard-state-card">No dashboard data available.</div>
        </div>
      </section>
    );
  }

  return (
    <section className="stats-section">
      <div className="container">
        <div className="stats-grid">
          <article className="stat-card">
            <h3>Total Drains</h3>
            <p className="stat-value">{kpi.totalDrains}</p>
            <p className="stat-description">Unique monitored drain nodes</p>
          </article>

          <article className="stat-card">
            <h3>Total Alerts</h3>
            <p className="stat-value">{kpi.totalAlerts}</p>
            <p className="stat-description">All alert records from backend</p>
          </article>

          <article className="stat-card">
            <h3>High Risk Alerts</h3>
            <p className="stat-value">{kpi.highRiskAlerts}</p>
            <p className="stat-description">Alerts with HIGH severity</p>
          </article>

          <article className="stat-card">
            <h3>Average DHI Score</h3>
            <p className="stat-value">{kpi.averageDhi.toFixed(2)}</p>
            <p className="stat-description">Average Drain Health Index</p>
          </article>
        </div>

        <div className="dashboard-charts-grid">
          <article className="dashboard-chart-card">
            <h3>DHI Trend</h3>
            <div className="chart-area">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={lineData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="timeLabel" />
                  <YAxis />
                  <Tooltip />
                  <Line
                    type="monotone"
                    dataKey="dhi_score"
                    stroke="#1f68ad"
                    strokeWidth={3}
                    dot={false}
                  />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </article>

          <article className="dashboard-chart-card">
            <h3>Alerts Distribution</h3>
            <div className="chart-area">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData}
                    dataKey="value"
                    nameKey="name"
                    innerRadius={55}
                    outerRadius={95}
                  >
                    {pieData.map((entry) => (
                      <Cell key={entry.name} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            </div>
          </article>

          <article className="dashboard-chart-card dashboard-chart-wide">
            <h3>Top Risk Drains (Average DHI)</h3>
            <div className="chart-area">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={topRiskDrains}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="drain_id" />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="avg_dhi" fill="#1f68ad" radius={[6, 6, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </article>
        </div>
      </div>
    </section>
  );
}

export default Dashboard;
